// ── BBT SITE JS ──

const LOGO_B64 = 'data:image/png;base64,';
const IMGS = {
  horse: 'data:image/jpeg;base64,',
  grey:  'data:image/jpeg;base64,',
  nba:   'data:image/jpeg;base64,',
  nrl:   'data:image/jpeg;base64,',
  nfl:   'data:image/jpeg;base64,',
  soccer:'data:image/jpeg;base64,',
};

// Fallback images per category
function getImg(cat) {
  const map = {
    horse: IMGS.horse, grey: IMGS.grey,
    nba: IMGS.nba, nrl: IMGS.nrl, nfl: IMGS.nfl,
    soccer: IMGS.soccer, ufc: IMGS.nba, mlb: IMGS.nfl,
  };
  return map[cat] || IMGS.horse;
}

// Star string
function stars(n) {
  return '★'.repeat(n) + '☆'.repeat(5-n);
}

// Format date
function fmtDate(iso) {
  if (!iso) return '';
  const d = new Date(iso);
  return d.toLocaleDateString('en-AU', { weekday:'short', day:'numeric', month:'short' });
}

// Cat colour class
function catClass(cat) {
  const m = { horse:'cat-horse', grey:'cat-grey', nrl:'cat-nrl', nba:'cat-nba', nfl:'cat-nfl', soccer:'cat-soccer', ufc:'cat-ufc', mlb:'cat-mlb' };
  return m[cat] || 'cat-horse';
}
function catTag(cat) {
  const m = { horse:'tag-pink', grey:'tag-teal', nrl:'tag-pink', nba:'tag-blue', nfl:'tag-green', soccer:'tag-blue', ufc:'tag-blue', mlb:'tag-blue' };
  return m[cat] || 'tag-blue';
}
function catLabel(tip) {
  return tip.categoryLabel || tip.category;
}

// ── CARD BUILDERS ──

function buildFeatCard(tip) {
  const img = tip.imageBase64 || getImg(tip.category);
  const href = `post.html?id=${tip.slug}`;
  return `
  <a href="${href}" class="card feat fade-in">
    <div class="card-img-wrap">
      <img class="card-img" src="data:image/jpeg;base64,${img}" alt="${tip.title}" loading="lazy">
    </div>
    <div class="card-body">
      <div class="card-cat ${catClass(tip.category)}">${catLabel(tip)}</div>
      <div class="card-title">${tip.headline || tip.title}</div>
      <div class="card-excerpt">${tip.analysis ? tip.analysis.substring(0,160)+'…' : ''}</div>
      <div class="card-meta">
        <span>${tip.dateFormatted || fmtDate(tip.date)}</span>
        <span class="sep">·</span>
        <span>${tip.venue}</span>
        ${tip.odds ? `<span class="sep">·</span><span class="card-odds">${tip.odds}</span>` : ''}
        ${tip.confidence ? `<span class="sep">·</span><span class="card-stars">${stars(tip.confidence)}</span>` : ''}
      </div>
    </div>
  </a>`;
}

function buildGridCard(tip) {
  const img = tip.imageBase64 || getImg(tip.category);
  const href = `post.html?id=${tip.slug}`;
  return `
  <a href="${href}" class="card grid">
    <div class="card-img-wrap">
      <img class="card-img" src="data:image/jpeg;base64,${img}" alt="${tip.title}" loading="lazy">
    </div>
    <div class="card-body">
      <div class="card-cat ${catClass(tip.category)}">${catLabel(tip)}</div>
      <div class="card-title">${tip.title}</div>
      <div class="card-meta">
        <span>${tip.dateFormatted || fmtDate(tip.date)}</span>
        <span class="sep">·</span>
        <span>${tip.meta || tip.venue}</span>
        ${tip.confidence ? `<span class="sep">·</span><span class="card-stars" style="font-size:11px;">${stars(tip.confidence)}</span>` : ''}
      </div>
    </div>
  </a>`;
}

function buildListCard(tip) {
  const img = tip.imageBase64 || getImg(tip.category);
  const href = `post.html?id=${tip.slug}`;
  return `
  <a href="${href}" class="card list">
    <div class="card-img-wrap">
      <img class="card-img" src="data:image/jpeg;base64,${img}" alt="${tip.title}" loading="lazy">
    </div>
    <div class="card-body">
      <div class="card-cat ${catClass(tip.category)}">${catLabel(tip)}</div>
      <div class="card-title">${tip.title}</div>
      <div class="card-meta">
        <span>${tip.dateFormatted || fmtDate(tip.date)}</span>
        <span class="sep">·</span>
        <span>${tip.meta || tip.venue}</span>
      </div>
    </div>
  </a>`;
}

function buildSkeleton(type = 'grid', count = 4) {
  const h = type === 'feat' ? 240 : type === 'list' ? 96 : 150;
  return Array(count).fill(0).map(() => `
    <div class="skeleton-card">
      <div class="skeleton skeleton-img" style="height:${h}px;"></div>
      <div class="skeleton skeleton-line" style="margin:12px 16px 0;"></div>
      <div class="skeleton skeleton-line short" style="margin:8px 16px 12px;"></div>
    </div>`).join('');
}

// ── TICKER BUILD ──
function buildTicker(tips) {
  const catDots = { horse: 'var(--pink)', grey: 'var(--teal)', nrl: 'var(--pink)', nba: '#e8a060', nfl: '#60c870', soccer: '#a0abf0', ufc: '#e87840', mlb: 'var(--lavender)' };
  const items = tips.map(t => `
    <span class="ticker-item">
      <span class="tdot" style="background:${catDots[t.category]||'var(--periwinkle)'}"></span>
      ${t.categoryLabel} — ${t.title}${t.odds ? ' — ' + t.odds : ''}
    </span>`).join('');
  return items + items; // duplicate for seamless loop
}

// ── DATA FETCH ──
async function loadTips() {
  try {
    const r = await fetch('data/tips.json?_=' + Date.now());
    const d = await r.json();
    return d.tips || [];
  } catch(e) {
    console.warn('Tips load failed:', e);
    return [];
  }
}

// ── HOMEPAGE RENDER ──
async function renderHomepage() {
  const tips = await loadTips();
  if (!tips.length) return;

  // Ticker
  const ticker = document.getElementById('ticker-track');
  if (ticker) ticker.innerHTML = buildTicker(tips);

  // Latest — featured
  const featured = tips.find(t => t.featured) || tips[0];
  const sideItems = tips.filter(t => t.id !== featured.id).slice(0, 2);
  const featEl = document.getElementById('feat-card');
  const sideEl = document.getElementById('side-cards');
  if (featEl) featEl.innerHTML = buildFeatCard(featured);
  if (sideEl) sideEl.innerHTML = sideItems.map(buildGridCard).join('');

  // Horse Racing
  renderSection('horse-grid', tips.filter(t => t.category === 'horse'), 'grid', 4);
  // Greyhounds
  renderSection('grey-grid', tips.filter(t => t.category === 'grey'), 'grid', 4);
  // NBA
  renderSection('nba-grid', tips.filter(t => t.category === 'nba'), 'grid', 4);
  // NRL
  renderSection('nrl-grid', tips.filter(t => t.category === 'nrl'), 'grid', 3);
  // NFL
  renderSection('nfl-list', tips.filter(t => t.category === 'nfl'), 'list', 4);
  // Soccer
  renderSection('soccer-list', tips.filter(t => t.category === 'soccer'), 'list', 4);

  // See All counts
  document.querySelectorAll('[data-count-cat]').forEach(el => {
    const cat = el.dataset.countCat;
    const count = tips.filter(t => t.category === cat).length;
    el.textContent = count ? `All ${el.dataset.countLabel} (${count}) →` : `All ${el.dataset.countLabel} →`;
  });
}

function renderSection(id, items, type = 'grid', max = 4) {
  const el = document.getElementById(id);
  if (!el) return;
  const fn = type === 'list' ? buildListCard : buildGridCard;
  if (!items.length) {
    el.innerHTML = `<p style="color:var(--text-dim);font-size:13px;padding:20px 0;">No tips available yet — check back tomorrow morning.</p>`;
    return;
  }
  el.innerHTML = items.slice(0, max).map(fn).join('');
  el.classList.add('stagger');
}

// ── CATEGORY PAGE RENDER ──
async function renderCategoryPage() {
  const params = new URLSearchParams(window.location.search);
  const cat = params.get('cat') || 'all';
  const tips = await loadTips();

  // Update title/heading
  const catNames = { all: 'All Tips', horse: 'Horse Racing', grey: 'Greyhounds', nba: 'NBA', nrl: 'NRL', nfl: 'NFL', soccer: 'Soccer', ufc: 'UFC', mlb: 'MLB' };
  const titleEl = document.getElementById('cat-title');
  if (titleEl) titleEl.textContent = catNames[cat] || 'All Tips';

  // Filter buttons
  document.querySelectorAll('.filter-btn').forEach(btn => {
    btn.classList.toggle('active', btn.dataset.cat === cat);
    btn.addEventListener('click', () => {
      const url = new URL(window.location);
      url.searchParams.set('cat', btn.dataset.cat);
      window.history.pushState({}, '', url);
      document.querySelectorAll('.filter-btn').forEach(b => b.classList.remove('active'));
      btn.classList.add('active');
      const filtered = btn.dataset.cat === 'all' ? tips : tips.filter(t => t.category === btn.dataset.cat);
      renderGrid('cat-grid', filtered);
    });
  });

  const filtered = cat === 'all' ? tips : tips.filter(t => t.category === cat);
  renderGrid('cat-grid', filtered);
}

function renderGrid(id, items) {
  const el = document.getElementById(id);
  if (!el) return;
  if (!items.length) {
    el.innerHTML = `<div style="grid-column:1/-1;padding:60px 0;text-align:center;color:var(--text-dim);">No tips in this category yet.</div>`;
    return;
  }
  el.innerHTML = items.map(buildGridCard).join('');
  el.classList.add('stagger');
}

// ── POST PAGE RENDER ──
async function renderPostPage() {
  const params = new URLSearchParams(window.location.search);
  const slug = params.get('id');
  if (!slug) { window.location = 'index.html'; return; }

  const tips = await loadTips();
  const tip = tips.find(t => t.slug === slug || t.id === slug);
  if (!tip) {
    document.getElementById('post-content').innerHTML = `<div class="post-body"><p>Tip not found. <a href="index.html" style="color:var(--teal);">← Back home</a></p></div>`;
    return;
  }

  document.title = `${tip.title} — Best Betting Tips`;
  const img = tip.imageBase64 || getImg(tip.category);

  // Hero
  const heroEl = document.getElementById('post-hero');
  if (heroEl) heroEl.innerHTML = `
    <img class="post-hero-img" src="data:image/jpeg;base64,${img}" alt="${tip.title}">
    <div class="post-hero-overlay"></div>
    <div class="post-hero-content">
      <div class="post-meta-row">
        <span class="tag ${catTag(tip.category)}">${catLabel(tip)}</span>
        <span style="font-size:12px;color:var(--text-muted);">${tip.dateFormatted || fmtDate(tip.date)}</span>
        <span style="font-size:12px;color:var(--text-muted);">${tip.venue}</span>
      </div>
      <h1 class="post-title">${tip.headline || tip.title}</h1>
    </div>`;

  // Stats
  const statsEl = document.getElementById('post-stats');
  if (statsEl && (tip.odds || tip.confidence)) {
    statsEl.innerHTML = `
      ${tip.venue ? `<div class="stat-card"><div class="stat-label">Venue</div><div class="stat-value" style="font-size:16px;color:var(--teal)">${tip.venue}</div></div>` : ''}
      ${tip.odds ? `<div class="stat-card"><div class="stat-label">Odds</div><div class="stat-value" style="color:var(--teal)">${tip.odds}</div></div>` : ''}
      ${tip.confidence ? `<div class="stat-card"><div class="stat-label">Confidence</div><div class="stat-value card-stars" style="font-size:22px;">${stars(tip.confidence)}</div></div>` : ''}`;
  }

  // Body
  const bodyEl = document.getElementById('post-analysis');
  if (bodyEl) bodyEl.innerHTML = `<p>${tip.analysis || ''}</p>`;

  // Related
  const relEl = document.getElementById('related-grid');
  if (relEl) {
    const related = tips.filter(t => t.id !== tip.id && t.category === tip.category).slice(0, 3);
    if (related.length) relEl.innerHTML = related.map(buildGridCard).join('');
    else relEl.innerHTML = tips.filter(t => t.id !== tip.id).slice(0, 3).map(buildGridCard).join('');
    relEl.classList.add('stagger');
  }
}

// ── NAV ──
function initNav() {
  const hamburger = document.getElementById('nav-hamburger');
  const navLinks = document.getElementById('nav-links');
  if (hamburger && navLinks) {
    hamburger.addEventListener('click', () => {
      navLinks.classList.toggle('open');
    });
  }
  // Active nav link
  const page = window.location.pathname.split('/').pop() || 'index.html';
  document.querySelectorAll('.nav-links a').forEach(a => {
    if (a.getAttribute('href') === page) a.classList.add('active');
  });
}

// ── NEWSLETTER ──
function initNewsletter() {
  document.querySelectorAll('.nl-form').forEach(form => {
    form.addEventListener('submit', e => {
      e.preventDefault();
      const input = form.querySelector('.nl-input');
      const btn = form.querySelector('.nl-btn');
      if (input.value && input.value.includes('@')) {
        btn.textContent = 'Subscribed ✓';
        btn.style.background = '#27ae60';
        input.value = '';
        setTimeout(() => { btn.textContent = 'Subscribe'; btn.style.background = ''; }, 3000);
      }
    });
  });
}

// ── INIT ──
document.addEventListener('DOMContentLoaded', () => {
  initNav();
  initNewsletter();

  const page = document.body.dataset.page;
  if (page === 'home') renderHomepage();
  else if (page === 'category') renderCategoryPage();
  else if (page === 'post') renderPostPage();
});
